<?php $prefix=$signaturePrefix??'operation';$firstLabel=$signatureFirstLabel??'Firma de usuario';$secondLabel=$signatureSecondLabel??'Firma de responsable'; ?>
<section class="vo-form-section" data-signature-group><h3>Fotografías y firmas</h3><div class="vo-field"><label for="<?= $prefix ?>-photos">Fotografías <span>(opcional)</span></label><input class="vo-input" id="<?= $prefix ?>-photos" type="file" name="photos[]" accept="image/jpeg,image/png,image/webp" capture="environment" multiple><small class="vo-field__help">JPEG, PNG o WebP; máximo 5 MB por imagen.</small></div><div class="vo-form-grid"><?php foreach([['user_signature',$firstLabel],['responsible_signature',$secondLabel]]as[$name,$label]): ?><div class="vo-field"><label><?= htmlspecialchars($label,ENT_QUOTES,'UTF-8') ?></label><canvas width="520" height="180" data-signature-canvas style="width:100%;max-width:520px;border:1px solid currentColor;touch-action:none;background:#fff"></canvas><input type="hidden" name="<?= $name ?>" data-signature-input><button class="vo-btn vo-btn--subtle" type="button" data-signature-clear>Limpiar firma</button></div><?php endforeach; ?></div></section>
